1→export const NODE_ENV = 'NODE_ENV';
2→export const PORT = 'PORT';
3→export const GLOBAL_PREFIX = 'GLOBAL_PREFIX';
4→export const SERVER_NAME = 'SERVER_NAME';
5→export const IS_COMPACT_LOGS = 'IS_COMPACT_LOGS';
6→export const IS_JSON_LIKE_LOGS = 'IS_JSON_LIKE_LOGS';
7→export const GRACEFUL_SHUTDOWN_DELAY = 'GRACEFUL_SHUTDOWN_DELAY';
